import { createClient } from '@/lib/supabase/server'
import { createClient as createSupabaseClient } from '@supabase/supabase-js'
import type { EntityType, TimelineEventType } from './types'

type SupabaseClient = ReturnType<typeof createSupabaseClient>

/** Remove characters that Postgres JSONB cannot handle */
function sanitizeForJson(text: string): string {
  // eslint-disable-next-line no-control-regex
  return text.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F]/g, '')
    .replace(/[\uD800-\uDFFF]/g, '')
}

/** Sanitize all string values in an object for JSONB storage */
function sanitizeEventData(data: Record<string, unknown>): Record<string, unknown> {
  const result: Record<string, unknown> = {}
  for (const [key, value] of Object.entries(data)) {
    if (typeof value === 'string') {
      result[key] = sanitizeForJson(value)
    } else if (value !== null && typeof value === 'object' && !Array.isArray(value)) {
      result[key] = sanitizeEventData(value as Record<string, unknown>)
    } else {
      result[key] = value
    }
  }
  return result
}

export interface TimelineEvent {
  orgId: string
  entityType: EntityType
  entityId: string
  eventType: TimelineEventType
  eventData?: Record<string, unknown>
  channelSource?: string
  relatedEntityType?: EntityType
  relatedEntityId?: string
  occurredAt?: string
}

/**
 * Write a timeline event to entity_timeline.
 * Fire-and-forget: logs errors but never throws.
 * Accepts optional supabaseClient for non-SSR callers (e.g. synthesizer.ts).
 */
export async function writeTimelineEvent(
  event: TimelineEvent,
  supabaseClient?: SupabaseClient
): Promise<void> {
  try {
    const supabase = supabaseClient ?? (await createClient())
    if (!supabase) return

    const { error } = await supabase
      .from('entity_timeline')
      .insert({
        org_id: event.orgId,
        entity_type: event.entityType,
        entity_id: event.entityId,
        event_type: event.eventType,
        event_data: event.eventData ? sanitizeEventData(event.eventData) : {},
        channel_source: event.channelSource ?? null,
        related_entity_type: event.relatedEntityType ?? null,
        related_entity_id: event.relatedEntityId ?? null,
        occurred_at: event.occurredAt ?? new Date().toISOString(),
      })

    if (error) {
      console.error('[timeline-writer] Failed to write timeline event:', error.message)
    }
  } catch (err) {
    console.error('[timeline-writer] Unexpected error:', err)
  }
}

/** Write a task-related timeline event */
export async function writeTaskEvent(
  orgId: string,
  taskId: string,
  eventType: Extract<TimelineEventType, 'task_created' | 'task_updated' | 'task_completed'>,
  eventData?: Record<string, unknown>,
  supabaseClient?: SupabaseClient
): Promise<void> {
  return writeTimelineEvent(
    {
      orgId,
      entityType: 'task',
      entityId: taskId,
      eventType,
      eventData,
    },
    supabaseClient
  )
}

/** Write a message-related timeline event */
export async function writeMessageEvent(
  orgId: string,
  messageId: string,
  eventType: Extract<TimelineEventType, 'message_received' | 'message_sent'>,
  eventData?: Record<string, unknown>,
  channelSource?: string,
  supabaseClient?: SupabaseClient
): Promise<void> {
  return writeTimelineEvent(
    {
      orgId,
      entityType: 'channel_message',
      entityId: messageId,
      eventType,
      eventData,
      channelSource,
    },
    supabaseClient
  )
}

/** Write a contact-related timeline event */
export async function writeContactEvent(
  orgId: string,
  contactId: string,
  eventType: Extract<TimelineEventType, 'contact_created' | 'contact_updated'>,
  eventData?: Record<string, unknown>,
  supabaseClient?: SupabaseClient
): Promise<void> {
  return writeTimelineEvent(
    {
      orgId,
      entityType: 'contact',
      entityId: contactId,
      eventType,
      eventData,
    },
    supabaseClient
  )
}
